 7→import org.springframework.http.HttpStatus;
 8→import org.springframework.http.MediaType;
 9→import org.springframework.security.config.annotation.web.builders.HttpSecurity;
10→import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
11→import org.springframework.security.config.annotation.web.configurers.AbstractHttpConfigurer;
12→import org.springframework.security.config.http.SessionCreationPolicy;
13→import org.springframework.security.web.SecurityFilterChain;
14→import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
15→
16→import java.util.Map;
17→
18→/**
19→ * Spring Security 配置
20→ */
21→@Configuration
22→@EnableWebSecurity
23→@RequiredArgsConstructor
24→public class SecurityConfig {
25→
26→    private final JwtAuthenticationFilter jwtAuthenticationFilter;
27→    private final ObjectMapper objectMapper;
28→
29→    @Bean
30→    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
31→        http
32→            .csrf(AbstractHttpConfigurer::disable)
33→            .sessionManagement(session -> session.sessionCreationPolicy(SessionCreationPolicy.STATELESS))
34→            .authorizeHttpRequests(auth -> auth
35→                .requestMatchers("/api/auth/**").permitAll()
36→                .requestMatchers("/api/admin/**").hasRole("ADMIN")
37→                .requestMatchers("/api/**").authenticated()
38→                .anyRequest().permitAll()
39→            )
40→            .addFilterBefore(jwtAuthenticationFilter, UsernamePasswordAuthenticationFilter.class)
41→            .exceptionHandling(ex -> ex
42→                .authenticationEntryPoint((request, response, authException) -> {
43→                    response.setStatus(HttpStatus.UNAUTHORIZED.value());
44→                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
45→                    response.setCharacterEncoding("UTF-8");
46→                    String body = objectMapper.writeValueAsString(
47→                            Map.of("code", 401, "message", "未登录或登录已过期", "data", ""));
48→                    response.getWriter().write(body);
49→                })
50→                .accessDeniedHandler((request, response, accessDeniedException) -> {
51→                    response.setStatus(HttpStatus.FORBIDDEN.value());
52→                    response.setContentType(MediaType.APPLICATION_JSON_VALUE);
53→                    response.setCharacterEncoding("UTF-8");
54→                    String body = objectMapper.writeValueAsString(
55→                            Map.of("code", 403, "message", "无权限访问", "data", ""));
56→                    response.getWriter().write(body);
57→                })
58→            );
59→
60→        return http.build();
61→    }
