 3→import com.exam.util.JwtUtil;
 4→import jakarta.servlet.FilterChain;
 5→import jakarta.servlet.ServletException;
 6→import jakarta.servlet.http.HttpServletRequest;
 7→import jakarta.servlet.http.HttpServletResponse;
 8→import lombok.RequiredArgsConstructor;
 9→import lombok.extern.slf4j.Slf4j;
10→import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
11→import org.springframework.security.core.authority.SimpleGrantedAuthority;
12→import org.springframework.security.core.context.SecurityContextHolder;
13→import org.springframework.stereotype.Component;
14→import org.springframework.util.AntPathMatcher;
15→import org.springframework.util.StringUtils;
16→import org.springframework.web.filter.OncePerRequestFilter;
17→
18→import java.io.IOException;
19→import java.util.ArrayList;
20→import java.util.List;
21→
22→/**
23→ * JWT 认证过滤器：从 Authorization header 解析 token 并设置认证信息
24→ */
25→@Slf4j
26→@Component
27→@RequiredArgsConstructor
28→public class JwtAuthenticationFilter extends OncePerRequestFilter {
29→
30→    private static final String BEARER_PREFIX = "Bearer ";
31→    private static final AntPathMatcher PATH_MATCHER = new AntPathMatcher();
32→
33→    /** 白名单路径，直接放行不解析 token */
34→    private static final List<String> WHITE_LIST = List.of("/api/auth/**");
35→
36→    private final JwtUtil jwtUtil;
37→
38→    @Override
39→    protected void doFilterInternal(HttpServletRequest request,
40→                                    HttpServletResponse response,
41→                                    FilterChain filterChain) throws ServletException, IOException {
42→        String path = request.getRequestURI();
43→
44→        // 白名单路径直接放行
45→        boolean isWhiteListed = WHITE_LIST.stream()
46→                .anyMatch(pattern -> PATH_MATCHER.match(pattern, path));
47→        if (isWhiteListed) {
48→            filterChain.doFilter(request, response);
49→            return;
50→        }
51→
52→        // 解析 Authorization header
53→        String authHeader = request.getHeader("Authorization");
54→        if (StringUtils.hasText(authHeader) && authHeader.startsWith(BEARER_PREFIX)) {
55→            String token = authHeader.substring(BEARER_PREFIX.length());
56→            try {
57→                Long userId = jwtUtil.getUserId(token);
58→                Boolean isAdmin = jwtUtil.getIsAdmin(token);
59→
60→                // 构建权限列表
61→                List<SimpleGrantedAuthority> authorities = new ArrayList<>();
62→                if (Boolean.TRUE.equals(isAdmin)) {
63→                    authorities.add(new SimpleGrantedAuthority("ROLE_ADMIN"));
64→                }
65→                authorities.add(new SimpleGrantedAuthority("ROLE_USER"));
66→
67→                UsernamePasswordAuthenticationToken authentication =
68→                        new UsernamePasswordAuthenticationToken(userId, null, authorities);
69→                SecurityContextHolder.getContext().setAuthentication(authentication);
70→            } catch (Exception e) {
71→                // token 无效或过期，不设认证信息，后续 Security 会返回 401
72→                log.debug("[exam-system] JWT 解析失败: {}", e.getMessage());
73→            }
74→        }
75→
76→        filterChain.doFilter(request, response);
77→    }
78→}
