/** 获取当前登录用户信息 */
export function useAuth() {
  const { data: user, isLoading, isError } = useQuery<User>({
    queryKey: ["auth", "me"],
    queryFn: () => get<User>("/api/auth/me"),
    staleTime: 5 * 60 * 1000,
    retry: false,
  })

  return {
    user,
    isAdmin: user?.isAdmin ?? false,
    isLoading,
    isError,
  }
}

