import { useState, useEffect } from "react"
import { createFileRoute, useNavigate, useParams } from "@tanstack/react-router"
import { useQuery } from "@tanstack/react-query"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Switch } from "@/components/ui/switch"
import { Select, SelectTrigger, SelectContent, SelectItem, SelectValue } from "@/components/ui/select"
import { useUpdateExam } from "@/hooks/use-admin-exams"
import { get } from "@/lib/api"
import type { Exam, AccessMode } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/edit")({
  component: EditExamPage,
})

function EditExamPage() {
  const { t } = useTranslation()
  const navigate = useNavigate()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/edit" })
  const examId = Number(id)
  const updateMutation = useUpdateExam()

  // 获取试卷详情（复用考生端接口）
  const { data: exam, isLoading } = useQuery<Exam>({
    queryKey: ["exam-detail", examId],
    queryFn: () => get<Exam>(`/api/exams/${examId}`),
    enabled: examId > 0,
  })

  const [title, setTitle] = useState("")
  const [timeLimitMin, setTimeLimitMin] = useState(60)
  const [questionCount, setQuestionCount] = useState(0)
  const [showAnswer, setShowAnswer] = useState(false)
  const [showAnalysis, setShowAnalysis] = useState(false)
  const [maxAttempts, setMaxAttempts] = useState(1)
  const [accessMode, setAccessMode] = useState<AccessMode>("open")

  // 数据加载后填充表单
  useEffect(() => {
    if (!exam) return
    setTitle(exam.title)
    setTimeLimitMin(exam.timeLimitMin)
    setQuestionCount(exam.questionCount)
    setShowAnswer(exam.showAnswer)
    setShowAnalysis(exam.showAnalysis)
    setMaxAttempts(exam.maxAttempts)
    setAccessMode(exam.accessMode)
  }, [exam])

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    updateMutation.mutate(
      { id: examId, title, timeLimitMin, questionCount, showAnswer, showAnalysis, maxAttempts, accessMode },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          navigate({ to: "/admin/exams" })
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  return (
    <div className="mx-auto max-w-2xl space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.editExam")}</h1>
        <Button variant="outline" onClick={() => navigate({ to: "/admin/exams" })}>
          {t("common.back")}
        </Button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="space-y-2">
          <Label>{t("admin.examTitle")}</Label>
          <Input value={title} onChange={(e) => setTitle(e.target.value)} required />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.timeLimit")}</Label>
          <Input
            type="number"
            min={1}
            value={timeLimitMin}
            onChange={(e) => setTimeLimitMin(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.questionCount")}</Label>
          <Input
            type="number"
            min={0}
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.maxAttempts")}</Label>
          <Input
            type="number"
            min={1}
            value={maxAttempts}
            onChange={(e) => setMaxAttempts(Number(e.target.value))}
            required
          />
        </div>

        <div className="space-y-2">
          <Label>{t("admin.accessMode")}</Label>
          <Select value={accessMode} onValueChange={(v) => setAccessMode(v as AccessMode)}>
            <SelectTrigger>
              <SelectValue />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="open">{t("admin.accessOpen")}</SelectItem>
              <SelectItem value="whitelist">{t("admin.accessWhitelist")}</SelectItem>
            </SelectContent>
          </Select>
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnswer")}</Label>
          <Switch checked={showAnswer} onCheckedChange={setShowAnswer} />
        </div>

        <div className="flex items-center justify-between rounded-md border p-3">
          <Label>{t("admin.showAnalysis")}</Label>
          <Switch checked={showAnalysis} onCheckedChange={setShowAnalysis} />
        </div>

        <div className="flex justify-end gap-2 pt-4">
          <Button
            type="button"
            variant="outline"
            onClick={() => navigate({ to: "/admin/exams" })}
          >
            {t("common.cancel")}
          </Button>
          <Button type="submit" disabled={updateMutation.isPending}>
            {t("common.save")}
          </Button>
        </div>
      </form>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Pencil, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { QuestionForm } from "@/components/question-form"
import {
  useQuestionList,
  useAddQuestion,
  useUpdateQuestion,
  useDeleteQuestion,
} from "@/hooks/use-admin-questions"
import type { Question } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/questions")({
  component: ManageQuestionsPage,
})

function ManageQuestionsPage() {
  const { t } = useTranslation()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/questions" })
  const examId = Number(id)

  const { data: questions, isLoading } = useQuestionList(examId)
  const addMutation = useAddQuestion()
  const updateMutation = useUpdateQuestion()
  const deleteMutation = useDeleteQuestion()

  const [showAddDialog, setShowAddDialog] = useState(false)
  const [editingQuestion, setEditingQuestion] = useState<Question | null>(null)
  const [deleteTarget, setDeleteTarget] = useState<Question | null>(null)

  const handleAdd = (data: Partial<Question>) => {
    addMutation.mutate(
      { examId, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.addQuestionSuccess"))
          setShowAddDialog(false)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleUpdate = (data: Partial<Question>) => {
    if (!editingQuestion) return
    updateMutation.mutate(
      { examId, id: editingQuestion.id, ...data },
      {
        onSuccess: () => {
          toast.success(t("admin.updateSuccess"))
          setEditingQuestion(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleDelete = () => {
    if (!deleteTarget) return
    deleteMutation.mutate(
      { examId, id: deleteTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.deleteSuccess"))
          setDeleteTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  /** 截断文本显示 */
  const truncate = (text: string, maxLen = 50) =>
    text.length > maxLen ? `${text.slice(0, maxLen)}...` : text

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <h1 className="text-xl font-semibold">{t("admin.manageQuestions")}</h1>
        <Button onClick={() => setShowAddDialog(true)}>
          <Plus className="h-4 w-4" />
          {t("admin.addQuestion")}
        </Button>
      </div>

      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !questions?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead className="w-16">#</TableHead>
              <TableHead>{t("admin.questionContent")}</TableHead>
              <TableHead className="w-24">{t("admin.correctAnswer")}</TableHead>
              <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {questions.map((q) => (
              <TableRow key={q.id}>
                <TableCell>{q.sortOrder}</TableCell>
                <TableCell>{truncate(q.content)}</TableCell>
                <TableCell>{q.correctAnswer}</TableCell>
                <TableCell>
                  <div className="flex justify-end gap-1">
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.edit")}
                      onClick={() => setEditingQuestion(q)}
                    >
                      <Pencil className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("common.delete")}
                      onClick={() => setDeleteTarget(q)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {/* 新增题目弹窗 */}
      <Dialog open={showAddDialog} onOpenChange={setShowAddDialog}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.addQuestion")}</DialogTitle>
          </DialogHeader>
          <QuestionForm onSubmit={handleAdd} onCancel={() => setShowAddDialog(false)} />
        </DialogContent>
      </Dialog>

      {/* 编辑题目弹窗 */}
      <Dialog open={!!editingQuestion} onOpenChange={(open) => !open && setEditingQuestion(null)}>
        <DialogContent className="max-w-2xl">
          <DialogHeader>
            <DialogTitle>{t("admin.editQuestion")}</DialogTitle>
          </DialogHeader>
          {editingQuestion && (
            <QuestionForm
              defaultValues={editingQuestion}
              onSubmit={handleUpdate}
              onCancel={() => setEditingQuestion(null)}
            />
          )}
        </DialogContent>
      </Dialog>

      {/* 删除确认弹窗 */}
      <Dialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmDelete")}</DialogTitle>
            <DialogDescription>{t("admin.confirmDeleteQuestionDesc")}</DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setDeleteTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleDelete} disabled={deleteMutation.isPending}>
              {t("common.delete")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { toast } from "sonner"
import { Plus, Trash2 } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from "@/components/ui/dialog"
import { useWhitelist, useAddWhitelist, useRemoveWhitelist } from "@/hooks/use-admin-whitelist"
import type { User } from "@/types"

export const Route = createFileRoute("/_layout/admin/exams/$id/whitelist")({
  component: WhitelistPage,
})

function WhitelistPage() {
  const { t } = useTranslation()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/whitelist" })
  const examId = Number(id)

  const { data: users, isLoading } = useWhitelist(examId)
  const addMutation = useAddWhitelist()
  const removeMutation = useRemoveWhitelist()

  const [inputValue, setInputValue] = useState("")
  const [removeTarget, setRemoveTarget] = useState<User | null>(null)

  const handleAdd = () => {
    const rawIds = inputValue
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean)
      .map(Number)
      .filter((n) => !Number.isNaN(n) && n > 0)

    if (!rawIds.length) {
      toast.error(t("admin.invalidUserIds"))
      return
    }

    addMutation.mutate(
      { examId, userIds: rawIds },
      {
        onSuccess: () => {
          toast.success(t("admin.addWhitelistSuccess"))
          setInputValue("")
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  const handleRemove = () => {
    if (!removeTarget) return
    removeMutation.mutate(
      { examId, userId: removeTarget.id },
      {
        onSuccess: () => {
          toast.success(t("admin.removeWhitelistSuccess"))
          setRemoveTarget(null)
        },
        onError: (err) => toast.error(err.message),
      },
    )
  }

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">{t("admin.whitelist")}</h1>

      {/* 添加白名单 */}
      <div className="flex gap-2">
        <Input
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder={t("admin.whitelistInputPlaceholder")}
          className="max-w-md"
          onKeyDown={(e) => e.key === "Enter" && (e.preventDefault(), handleAdd())}
        />
        <Button onClick={handleAdd} disabled={addMutation.isPending}>
          <Plus className="h-4 w-4" />
          {t("admin.addUser")}
        </Button>
      </div>

      {/* 白名单列表 */}
      {isLoading ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
      ) : !users?.length ? (
        <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
      ) : (
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>{t("admin.username")}</TableHead>
              <TableHead>{t("admin.displayName")}</TableHead>
              <TableHead className="w-24 text-right">{t("common.actions")}</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {users.map((user) => (
              <TableRow key={user.id}>
                <TableCell>{user.username}</TableCell>
                <TableCell>{user.displayName}</TableCell>
                <TableCell>
                  <div className="flex justify-end">
                    <Button
                      variant="ghost"
                      size="icon"
                      title={t("admin.removeUser")}
                      onClick={() => setRemoveTarget(user)}
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      )}

      {/* 移除确认弹窗 */}
      <Dialog open={!!removeTarget} onOpenChange={(open) => !open && setRemoveTarget(null)}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>{t("admin.confirmRemove")}</DialogTitle>
            <DialogDescription>
              {t("admin.confirmRemoveWhitelistDesc", { name: removeTarget?.displayName })}
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <Button variant="outline" onClick={() => setRemoveTarget(null)}>
              {t("common.cancel")}
            </Button>
            <Button variant="destructive" onClick={handleRemove} disabled={removeMutation.isPending}>
              {t("common.confirm")}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  )
}

import { useState } from "react"
import { createFileRoute, useParams } from "@tanstack/react-router"
import { useTranslation } from "react-i18next"
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs"
import { Button } from "@/components/ui/button"
import {
  Table,
  TableHeader,
  TableBody,
  TableRow,
  TableHead,
  TableCell,
} from "@/components/ui/table"
import { useScoreAnalysis, useQuestionAnalysis } from "@/hooks/use-admin-analysis"

export const Route = createFileRoute("/_layout/admin/exams/$id/analysis")({
  component: AnalysisPage,
})

function AnalysisPage() {
  const { t } = useTranslation()
  const { id } = useParams({ from: "/_layout/admin/exams/$id/analysis" })
  const examId = Number(id)

  return (
    <div className="space-y-4">
      <h1 className="text-xl font-semibold">{t("admin.analysisTab")}</h1>
      <Tabs defaultValue="scores">
        <TabsList>
          <TabsTrigger value="scores">{t("admin.scoreAnalysis")}</TabsTrigger>
          <TabsTrigger value="questions">{t("admin.questionAnalysis")}</TabsTrigger>
        </TabsList>
        <TabsContent value="scores">
          <ScoreTab examId={examId} />
        </TabsContent>
        <TabsContent value="questions">
          <QuestionTab examId={examId} />
        </TabsContent>
      </Tabs>
    </div>
  )
}

/** 得分情况 Tab */
function ScoreTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const [page, setPage] = useState(1)
  const pageSize = 10
  const { data, isLoading } = useScoreAnalysis(examId, page, pageSize)

  const totalPages = data ? Math.ceil(data.total / pageSize) : 0

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.records.length) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-4">
      <Table>
        <TableHeader>
          <TableRow>
            <TableHead>{t("admin.displayName")}</TableHead>
            <TableHead>{t("admin.score")}</TableHead>
            <TableHead>{t("admin.startTime")}</TableHead>
            <TableHead>{t("admin.endTime")}</TableHead>
            <TableHead>{t("admin.attemptNo")}</TableHead>
          </TableRow>
        </TableHeader>
        <TableBody>
          {data.records.map((r, idx) => (
            <TableRow key={`${r.userId}-${r.attemptNo}-${idx}`}>
              <TableCell>{r.displayName}</TableCell>
              <TableCell>{r.score}</TableCell>
              <TableCell>{new Date(r.startTime).toLocaleString()}</TableCell>
              <TableCell>{r.endTime ? new Date(r.endTime).toLocaleString() : "-"}</TableCell>
              <TableCell>{r.attemptNo}</TableCell>
            </TableRow>
          ))}
        </TableBody>
      </Table>

      {totalPages > 1 && (
        <div className="flex items-center justify-end gap-2">
          <Button
            variant="outline"
            size="sm"
            disabled={page <= 1}
            onClick={() => setPage((p) => p - 1)}
          >
            {t("admin.prevPage")}
          </Button>
          <span className="text-sm text-muted-foreground">
            {page} / {totalPages}
          </span>
          <Button
            variant="outline"
            size="sm"
            disabled={page >= totalPages}
            onClick={() => setPage((p) => p + 1)}
          >
            {t("admin.nextPage")}
          </Button>
        </div>
      )}
    </div>
  )
}

/** 题目分析 Tab */
function QuestionTab({ examId }: { examId: number }) {
  const { t } = useTranslation()
  const { data, isLoading } = useQuestionAnalysis(examId)

  if (isLoading) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.loading")}</div>
  }

  if (!data?.length) {
    return <div className="py-10 text-center text-muted-foreground">{t("common.noData")}</div>
  }

  return (
    <div className="space-y-3">
      {data.map((q) => {
        const ratePercent = Math.round(q.correctRate * 100)
        return (
          <div key={q.questionId} className="rounded-md border p-4 space-y-2">
            <p className="text-sm font-medium">
              {q.content.length > 80 ? `${q.content.slice(0, 80)}...` : q.content}
            </p>
            <div className="flex items-center gap-4 text-sm text-muted-foreground">
              <span>
                {t("admin.totalAnswered")}: {q.totalAnswered}
              </span>
              <span>
                {t("admin.correctCount")}: {q.correctCount}
              </span>
              <span>
                {t("admin.correctRate")}: {ratePercent}%
              </span>
            </div>
            {/* 正确率进度条 */}
            <div className="h-2 w-full rounded-full bg-muted">
              <div
                className="h-2 rounded-full bg-primary transition-all"
                style={{ width: `${ratePercent}%` }}
              />
            </div>
          </div>
        )
      })}
    </div>
  )
}

