import { useQuery, useMutation } from "@tanstack/react-query"
import { get, post } from "@/lib/api"
import type { PageResult } from "@/types"

/** 考生端试卷详情响应 */
export interface ExamDetail {
  id: number
  title: string
  status: string
  timeLimitMin: number
  questionCount: number
  maxAttempts: number
  showAnswer: boolean
  showAnalysis: boolean
  accessMode: string
  remainingAttempts: number | null
}

/** 开始考试响应 */
export interface StartExamResponse {
  recordId: number
  questions: Array<{
    id: number
    content: string
    optionA: string
    optionB: string
    optionC: string
    optionD: string
    sortOrder: number
  }>
}

/** 提交考试响应 */
export interface SubmitExamResponse {
  score: number
  status: string
}

/** 提交考试请求体 */
interface SubmitExamPayload {
  examId: number
  recordId: number
  answers: Array<{ questionId: number; answer: string }>
}

const EXAMS_KEY = "exams"

/** 考生端获取可参加的考试列表 */
export function useExamList(page: number, size: number) {
  return useQuery<PageResult<ExamDetail>>({
    queryKey: [EXAMS_KEY, page, size],
    queryFn: () =>
      get<PageResult<ExamDetail>>(`/api/exams?page=${page}&size=${size}`),
  })
}

/** 考生端获取单个考试详情 */
export function useExamDetail(id: number) {
  return useQuery<ExamDetail>({
    queryKey: [EXAMS_KEY, id],
    queryFn: () => get<ExamDetail>(`/api/exams/${id}`),
    enabled: id > 0,
  })
}

/** 开始考试 mutation */
export function useStartExam() {
  return useMutation<StartExamResponse, Error, number>({
    mutationFn: (examId) =>
      post<StartExamResponse>(`/api/exams/${examId}/start`),
  })
}

/** 提交考试 mutation */
export function useSubmitExam() {
  return useMutation<SubmitExamResponse, Error, SubmitExamPayload>({
    mutationFn: ({ examId, recordId, answers }) =>
      post<SubmitExamResponse>(`/api/exams/${examId}/submit`, {
        recordId,
        answers,
      }),
  })
}

import { useQuery } from "@tanstack/react-query"
import { get } from "@/lib/api"
import type { PageResult } from "@/types"

/** 考试记录详情响应 */
export interface RecordDetail {
  id: number
  examId: number
  examTitle: string
  score: number | null
  startTime: string
  endTime: string | null
  status: string
  attemptNo: number
  answers?: Array<{
    questionId: number
    content: string
    optionA: string
    optionB: string
    optionC: string
    optionD: string
    userAnswer: string
    isCorrect: boolean
    correctAnswer?: string
    analysis?: string
  }>
}

const RECORDS_KEY = "records"

/** 考生端获取考试记录列表 */
export function useRecordList(page: number, size: number) {
  return useQuery<PageResult<RecordDetail>>({
    queryKey: [RECORDS_KEY, page, size],
    queryFn: () =>
      get<PageResult<RecordDetail>>(`/api/records?page=${page}&size=${size}`),
  })
}

/** 考生端获取单条考试记录详情（含答题明细） */
export function useRecordDetail(id: number) {
  return useQuery<RecordDetail>({
    queryKey: [RECORDS_KEY, id],
    queryFn: () => get<RecordDetail>(`/api/records/${id}`),
    enabled: id > 0,
  })
}

